import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { AppStoreService } from '../../services/app-store.service';
import { AppDefinition } from '../../models/app-store.models';
import { BehaviorSubject, catchError, of, tap, switchMap } from 'rxjs';
import { ButtonModule } from 'primeng/button';
import { TableModule } from 'primeng/table';
import { TagModule } from 'primeng/tag';
import { CardModule } from 'primeng/card';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

@Component({
  selector: 'app-app-admin-panel',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    ButtonModule,
    TableModule,
    TagModule,
    CardModule,
    ProgressSpinnerModule,
  ],
  templateUrl: './app-admin-panel.component.html',
  styleUrls: ['./app-admin-panel.component.scss'],
})
export class AppAdminPanelComponent {
  apps: AppDefinition[] = [];
  loading = true;
  error: string | null = null;
  statusFilter$ = new BehaviorSubject<AppDefinition['status'] | 'ALL'>(
    'PENDING_REVIEW',
  );

  private readonly appStoreService = inject(AppStoreService);

  statusOptions: { label: string; value: AppDefinition['status'] | 'ALL' }[] = [
    { label: 'Pending Review', value: 'PENDING_REVIEW' },
    { label: 'Approved', value: 'APPROVED' },
    { label: 'Rejected', value: 'REJECTED' },
    { label: 'Suspended', value: 'SUSPENDED' },
    { label: 'All', value: 'ALL' },
  ];

  constructor() {
    this.statusFilter$
      .pipe(
        tap(() => {
          this.loading = true;
          this.error = null;
        }),
        switchMap((status) => {
          let params: Record<string, string> | undefined = undefined;
          if (status !== 'ALL') {
            params = { status };
          }
          return this.appStoreService.getApps(params).pipe(
            tap((apps) => {
              this.apps = apps;
              this.loading = false;
            }),
            catchError(() => {
              this.loading = false;
              this.error = 'Unable to load apps. Please try again.';
              return of([] as AppDefinition[]);
            }),
          );
        }),
      )
      .subscribe();
  }

  onStatusFilterChange(status: AppDefinition['status'] | 'ALL'): void {
    this.statusFilter$.next(status);
  }

  statusSeverity(
    status: AppDefinition['status'],
  ): 'success' | 'info' | 'warn' | 'danger' | 'secondary' {
    if (status === 'APPROVED') return 'success';
    if (status === 'PENDING_REVIEW') return 'warn';
    if (status === 'DRAFT') return 'secondary';
    if (status === 'SUSPENDED') return 'danger';
    return 'info';
  }

  statusLabel(status: AppDefinition['status']): string {
    return status
      .toLowerCase()
      .split('_')
      .map((part) => part[0].toUpperCase() + part.slice(1))
      .join(' ');
  }
}
